src/main.ts<pre><code>import { start, DEFAULT_REDUX_STATE } from "@pihanga2/core";
import { myInit } from "./app.pihanga";
import type { AppState } from "./app.types";

const initState: AppState = {
  ...DEFAULT_REDUX_STATE,   // required — seeds routing and framework slices
  title: "My App",
};

start(initState, [myInit]);
</code></pre>

src/app.types.ts<pre><code>import type { PiCardRef, ReduxState } from "@pihanga2/core";

export type AppState = ReduxState &amp; {
  title: string;
  activePage: PiCardRef;
};
</code></pre>

src/app.pihanga.ts<pre><code>import { type PiRegister } from "@pihanga2/core";
import type { AppState } from "./app.types";

export function myInit(register: PiRegister): void {
  // Register the top-level window card — page prop drives which card is shown
  register.window&lt;AppState&gt;({
    page: (s) =&gt; s.activePage,
  });

  // Register a named card instance
  register.card("page/home", {
    cardType: "my/page",
    title: (s: AppState) =&gt; s.title,
  });
}
</code></pre>

src/cards/counter/counter.types.ts<pre><code>import { createCardDeclaration, actionTypesToEvents } from "@pihanga2/core";

export const COUNTER_CARD = "my/counter";

export type CounterProps = {
  count: number;
  label?: string;
};

export type CounterEvents = {
  onIncrement: { delta: number };
  onReset: Record&lt;string, never&gt;;
};

// Factory function: CounterCard({ count: 0, label: "Hits" })
export const CounterCard = createCardDeclaration&lt;CounterProps, CounterEvents&gt;(
  COUNTER_CARD,
);

// Redux action types that map to CounterEvents
export const COUNTER_ACTIONS = actionTypesToEvents&lt;CounterEvents&gt;(COUNTER_CARD);
</code></pre>

src/cards/counter/counter.component.tsx<pre><code>import React from "react";
import { PiCardProps } from "@pihanga2/core";
import { CounterProps, CounterEvents } from "./counter.types";

export function CounterComponent({
  count,
  label = "Count",
  onIncrement,
  onReset,
}: PiCardProps&lt;CounterProps, CounterEvents&gt;) {
  return (
    &lt;div&gt;
      &lt;span&gt;{label}: {count}&lt;/span&gt;
      &lt;button onClick={() =&gt; onIncrement({ delta: 1 })}&gt;+1&lt;/button&gt;
      &lt;button onClick={() =&gt; onReset({})}&gt;Reset&lt;/button&gt;
    &lt;/div&gt;
  );
}
</code></pre>

src/cards/counter/index.ts<pre><code>import { registerCardComponent } from "@pihanga2/core";
import { COUNTER_CARD, COUNTER_ACTIONS } from "./counter.types";
import { CounterComponent } from "./counter.component";

registerCardComponent({
  name: COUNTER_CARD,
  component: CounterComponent,
  events: COUNTER_ACTIONS,
});
</code></pre>

src/app.pihanga.ts<pre><code>import { register } from "@pihanga2/core";
import { CounterCard } from "./cards/counter/counter.types";

register((r) =&gt; {
  r.card("page/myCounter", CounterCard({ count: 0, label: "Clicks" }));
});
</code></pre>

src/app.reducer.ts<pre><code>import { type PiRegister } from "@pihanga2/core";
import type { AppState } from "./app.types";

export function reducerInit(register: PiRegister): void {
  register.reducer.register&lt;AppState&gt;(
    "COUNTER/INCREMENT",
    (state, action) =&gt; {
      state.count += action.delta;
      return state;
    },
  );
}
</code></pre>
